/**
 * Tests for the PostToolUse heartbeat hook (#1912).
 *
 * Verifies UPDATE last_heartbeat fires + the rate-limit (5s) skips
 * subsequent calls within the window.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import Database from 'better-sqlite3';

import { heartbeat, __internals } from '../../posttool/heartbeat.js';
import { openDb, __resetDbForTests } from '../../lib/session-registry.js';
import { NOOP_CTX } from '../../lib/context.js';
import type { HookInput } from '../../types.js';

function makeInput(sid: string): HookInput {
  return {
    hook_event: 'PostToolUse',
    tool_name: 'Read',
    session_id: sid,
    tool_input: {},
  } as HookInput;
}

describe('posttool/heartbeat (#1912)', () => {
  let workDir: string;
  let dbPath: string;
  let prevEnv: string | undefined;

  beforeEach(() => {
    workDir = mkdtempSync(join(tmpdir(), 'ork-heartbeat-'));
    dbPath = join(workDir, 'sessions.db');
    prevEnv = process.env.ORK_SESSION_DB;
    process.env.ORK_SESSION_DB = dbPath;
    __resetDbForTests();
    // Reset the in-memory rate-limit cache so each test starts clean.
    __internals.lastBeat.clear();

    // Seed a running session with an OLD heartbeat so we can detect the bump.
    const db = openDb();
    db.prepare(
      `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, started_at, last_heartbeat, status)
       VALUES ('s-beat', 1, '/x', 'h', '/x', 0, 0, 'running')`,
    ).run();
    db.close();
    __resetDbForTests();
  });

  afterEach(() => {
    __resetDbForTests();
    __internals.lastBeat.clear();
    if (prevEnv === undefined) delete process.env.ORK_SESSION_DB;
    else process.env.ORK_SESSION_DB = prevEnv;
    rmSync(workDir, { recursive: true, force: true });
  });

  it('updates last_heartbeat on first PostToolUse for a sid', () => {
    const before = Math.floor(Date.now() / 1000);
    const res = heartbeat(makeInput('s-beat'), NOOP_CTX);
    expect(res.continue).toBe(true);

    const db = new Database(dbPath, { readonly: true });
    const row = db
      .prepare('SELECT last_heartbeat FROM sessions WHERE sid=?')
      .get('s-beat') as { last_heartbeat: number };
    db.close();
    expect(row.last_heartbeat).toBeGreaterThanOrEqual(before);
  });

  it('rate-limits subsequent calls within 5 seconds', () => {
    // First call writes (sets the cache).
    heartbeat(makeInput('s-beat'), NOOP_CTX);

    // Stamp the DB heartbeat to a known sentinel so we can detect a write.
    const db = openDb();
    db.prepare('UPDATE sessions SET last_heartbeat = 42 WHERE sid=?').run('s-beat');
    db.close();
    __resetDbForTests();

    // Immediately call again — should be skipped, sentinel remains.
    heartbeat(makeInput('s-beat'), NOOP_CTX);

    const dbRO = new Database(dbPath, { readonly: true });
    const row = dbRO
      .prepare('SELECT last_heartbeat FROM sessions WHERE sid=?')
      .get('s-beat') as { last_heartbeat: number };
    dbRO.close();
    expect(row.last_heartbeat).toBe(42);
  });

  it('writes again once the rate-limit window elapses', () => {
    heartbeat(makeInput('s-beat'), NOOP_CTX);

    // Rewind the cached timestamp past the window.
    __internals.lastBeat.set('s-beat', Date.now() - __internals.RATE_LIMIT_MS - 100);

    const before = Math.floor(Date.now() / 1000);
    heartbeat(makeInput('s-beat'), NOOP_CTX);

    const db = new Database(dbPath, { readonly: true });
    const row = db
      .prepare('SELECT last_heartbeat FROM sessions WHERE sid=?')
      .get('s-beat') as { last_heartbeat: number };
    db.close();
    expect(row.last_heartbeat).toBeGreaterThanOrEqual(before);
  });
});
